// Extraer datos del evento de scan y preparar payload para el scanner
const event = items[0].json;
const scanId = event.scanId;
const scanType = (event.requestedService || 'SAST').toUpperCase();
const targetUrl = event.targetUrl || '';
const targetRepo = event.targetRepo || '';
const tenantId = event.tenantId || '';

// Determinar a qué servicio .NET llamar según el tipo
let webhookUrl = '';
let payload = {};

if (scanType === 'SAST' || scanType === 'FULL') {
  // Code Quality Service (Semgrep)
  webhookUrl = 'http://code-quality-service:5001/api/n8n/semgrep/result-ready';
  payload = {
    scanId: scanId,
    filePath: '/mnt/semgrep/results/' + scanId + '.json',
    projectName: 'scan-' + scanId.substring(0,8)
  };
} else if (scanType === 'DAST' || scanType === 'CONTAINER') {
  // Vulnerability Service (ZAP/Trivy)
  webhookUrl = 'http://vulnerability-service:5001/api/v1/n8n/vulnerability-ready';
  const tool = scanType === 'CONTAINER' ? 'TRIVY' : 'ZAP';
  payload = {
    scanId: scanId,
    filePath: '/mnt/vulnerability/results/' + scanId + '.json',
    projectName: 'scan-' + scanId.substring(0,8),
    tool: tool
  };
} else {
  // Default: Security Gate Service
  webhookUrl = 'http://security-gate-service:5001/api/scan/result';
  payload = {
    scanId: scanId,
    result: 'PASS',
    findings: []
  };
}

return [{
  json: {
    webhookUrl: webhookUrl,
    payload: payload,
    scanType: scanType,
    scanId: scanId
  }
}];

// Log del resultado
const result = items[0].json;
console.log('Scan dispatched:', result.scanId, '->', result.scanType, '->', result.webhookUrl);
return items;
